Serial.Open();
string? line;
while ((line = Serial.ReadLine()) != null)
{
    double temp = double.Parse(line.Split('=')[1]);
    if (temp > 150 || temp < -50)
        Print("数据异常，跳过");
    else
        Print($"温度: {temp}°C");
}
Serial.Close();
Print("校验完成");
